export declare const healthFunctionalRouteHandlerTemplate = "import { normalizeError } from \"@sculptor/core\";\nimport type { FrameworkErrorHandler, Nxt, Req, Res, SculptorError, SculptorFunctionalHandler } from \"@sculptor/core\";\n\nimport { HealthService } from \"./health.service.js\";\n\nexport const healthHandler: SculptorFunctionalHandler<void> = async (\n  req: Req,\n  res: Res,\n  next: Nxt\n): Promise<void> => {\n  try {\n    if (req.path.endsWith(\"/ping\")) {\n      res.json({ message: \"pong\" });\n      return;\n    }\n\n    res.json(HealthService());\n  } catch (error) {\n    next(normalizeError(error));\n  }\n};\n\nexport const healthErrorHandler: FrameworkErrorHandler = (\n  error: SculptorError,\n  _req: Req,\n  res: Res,\n  next: Nxt\n): void => {\n  if (res.headersSent) {\n    next(error);\n    return;\n  }\n\n  res.status(500).json({\n    message: error.message,\n    code: error.code,\n    status: error.status\n  });\n};\n";
